// Client-side image resizing using HTML5 Canvas
const resizeImage = (file: File, maxWidth = 800): Promise<Blob> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = (event) => {
      const img = new window.Image();
      img.src = event.target?.result as string;
      img.onload = () => {
        const canvas = document.createElement('canvas');
        let width = img.width;
        let height = img.height;
        if (width > maxWidth) {
          height = Math.round((height * maxWidth) / width);
          width = maxWidth;
        }
        canvas.width = width;
        canvas.height = height;
        const ctx = canvas.getContext('2d');
        if (!ctx) {
          reject(new Error('Could not get canvas context'));
          return;
        }
        ctx.drawImage(img, 0, 0, width, height);
        canvas.toBlob((blob) => {
          if (blob) {
            resolve(blob);
          } else {
            reject(new Error('Canvas toBlob failed'));
          }
        }, 'image/jpeg', 0.85);
      };
      img.onerror = (err) => reject(err);
    };
    reader.onerror = (err) => reject(err);
  });
};

// Client-side upload of resized image to Supabase payment-proofs bucket
const uploadItineraryImage = async (file: File): Promise<string> => {
  const supabase = createClient();
  const fileExt = 'jpg'; // We compress canvas output to JPEG
  const fileName = `${Math.random().toString(36).substring(2, 15)}_${Date.now()}.${fileExt}`;
  const filePath = `${fileName}`;

  // Resize the image to max 800px width
  const resizedBlob = await resizeImage(file, 800);

  const { error: uploadError } = await supabase.storage
    .from('payment-proofs')
    .upload(filePath, resizedBlob, {
      contentType: 'image/jpeg'
    });

  if (uploadError) throw uploadError;

  const { data } = supabase.storage
    .from('payment-proofs')
    .getPublicUrl(filePath);

  return data.publicUrl;
};

const parseTimeToMinutes = (timeStr: string): number => {
  if (!timeStr) return 9999;
  const cleanStr = timeStr.trim().toUpperCase();
  
  // Try to parse AM/PM format first (e.g., "10:30 AM", "09:00 PM")
  const ampmMatch = cleanStr.match(/^(\d+):(\d+)\s*(AM|PM)$/);
  if (ampmMatch) {
    let hours = parseInt(ampmMatch[1], 10);
    const minutes = parseInt(ampmMatch[2], 10);
    const period = ampmMatch[3];
    
    if (period === 'PM' && hours < 12) {
      hours += 12;
    } else if (period === 'AM' && hours === 12) {
      hours = 0;
    }
    return hours * 60 + minutes;
  }
  
  // Try to parse standard 24-hour format "HH:MM"
  const standardMatch = cleanStr.match(/^(\d+):(\d+)$/);
  if (standardMatch) {
    const hours = parseInt(standardMatch[1], 10);
    const minutes = parseInt(standardMatch[2], 10);
    return hours * 60 + minutes;
  }
  
  // Fallback: if it's just a number, treat as hour
  const hourOnly = parseInt(cleanStr, 10);
  if (!isNaN(hourOnly)) {
    return hourOnly * 60;
  }
  
  return 9999; // Empty/unparseable times go to the end of the day
};

const sortItineraryChronologically = (blocks: InternalItineraryBlock[]): InternalItineraryBlock[] => {
  return [...blocks].sort((a, b) => {
    if (a.dayNumber !== b.dayNumber) {
      return a.dayNumber - b.dayNumber;
    }
    const minutesA = parseTimeToMinutes(a.startTime);
    const minutesB = parseTimeToMinutes(b.startTime);
    return minutesA - minutesB;
  });
};

