  const handleReceiveInvoice = async (po: any) => {
    const amount = parseFloat(invoiceAmount);
    const rate = parseFloat(invoiceExchangeRate) || 1.0;
    if (!invoiceNumber) {
      alert("Please enter an invoice number.");
      return;
    }
    if (isNaN(amount) || amount <= 0) {
      alert("Please enter a valid amount.");
      return;
    }

    const invoiceAmtLKR = amount * rate;
    const poAmtLKR = po.currency === 'USD' ? po.total_amount * rate : po.total_amount;
    const discrepancy = po.currency === invoiceCurrency ? (amount - po.total_amount) : (invoiceAmtLKR - poAmtLKR);
    const isTallied = Math.abs(discrepancy) < 0.01;

    try {
      const res = await saveSupplierInvoiceAction({
        purchase_order_id: po.id,
        invoice_number: invoiceNumber,
        invoice_date: invoiceDate || new Date().toISOString().split('T')[0],
        amount: amount,
        currency: invoiceCurrency,
        exchange_rate: rate,
        status: isTallied ? 'Confirmed' : 'Pending',
        is_tallied: isTallied,
        discrepancy_amount: discrepancy,
        attachment_url: invoiceAttachment || undefined,
        items: invoiceItems.map(item => ({
          purchase_order_item_id: item.purchase_order_item_id,
          description: item.description,
          quantity: parseFloat(item.quantity) || 0,
          unit_price: parseFloat(item.unit_price) || 0
        })) as any
      });

      if (res.success) {
        alert(isTallied ? "Invoice recorded and tallied!" : "Invoice recorded with discrepancy warning.");
        setInvoiceNumber('');
        setInvoiceAmount('');
        setInvoiceDate('');
        setInvoiceAttachment('');
        setInvoiceItems([]);
        setEnteringInvoicePoId(null);
        loadProcurementData(tourId);
      } else {
        alert("Failed to save invoice: " + res.error);
      }
    } catch (err: any) {
      alert("Error: " + err.message);
    }
  };

  const handleRecordAdvancePayment = async (poId: string) => {
    const amount = parseFloat(paymentAmount);
    const rate = parseFloat(paymentExchangeRate) || 1.0;
    if (isNaN(amount) || amount <= 0) {
      alert("Please enter a valid payment amount.");
      return;
    }

    const currentPO = purchaseOrders.find(p => p.id === poId);
    if (currentPO) {
      const poTotal = currentPO.total_amount || 0;
      // Get already paid advance payments
      const existingPaid = (currentPO.advance_payments || []).reduce((sum: number, p: any) => sum + Number(p.amount), 0);
      const totalPaidWithNew = existingPaid + amount;
      
      // If total advance payments settle or exceed the PO
      if (totalPaidWithNew >= poTotal) {
        const proceed = window.confirm(
          `You are recording an advance payment of ${paymentCurrency} ${amount.toFixed(2)}, which will bring the total advance payments to ${paymentCurrency} ${totalPaidWithNew.toFixed(2)} (PO Total: ${currentPO.currency || 'USD'} ${poTotal.toFixed(2)}).\n\n` +
          `For full settlements, it is recommended to record a Supplier Invoice first and log the payment against that invoice instead of as an advance.\n\n` +
          `Are you sure you want to proceed with recording this as an advance payment?`
        );
        if (!proceed) {
          return;
        }
      }
    }

    try {
      const res = await saveSupplierPaymentAction({
        supplier_invoice_id: null,
        purchase_order_id: poId,
        payment_date: paymentDate || new Date().toISOString().split('T')[0],
        amount: amount,
        payment_method: paymentMethod,
        payment_reference: paymentRef || undefined,
        notes: paymentNotes || undefined,
        currency: paymentCurrency,
        exchange_rate: rate,
        attachment_url: advancePaymentPayslipUrl || undefined
      });

      if (res.success) {
        alert("Advance payment recorded successfully!");
        setPaymentAmount('');
        setPaymentRef('');
        setPaymentNotes('');
        setPaymentDate('');
        setPaymentCurrency('USD');
        setPaymentExchangeRate('1.0');
        setAdvancePaymentPayslipUrl('');
        setActivePoForAdvancePayment(null);
        loadProcurementData(tourId);
      } else {
        alert("Failed to record advance payment: " + res.error);
      }
    } catch (err: any) {
      alert("Error: " + err.message);
    }
  };

