                          <span className="px-2.5 py-0.5 rounded-full text-[10px] font-bold bg-emerald-50 text-emerald-850 border border-emerald-150 uppercase tracking-wider">
                            {touristData?.preferences?.travel_style || 'Luxury'} Tier
                          </span>
